function getWorkflowSteps(report) {
    const status = report.status;
    const wasSentForRework = Boolean(report.dmaReviewNotes && status === "assigned");
    return [
        {
            title: "Reported",
            detail: "Citizen or operator submitted the reported leakage.",
            active: true,
            current: status === "new"
        },
        {
            title: wasSentForRework ? "Assigned Again" : "Assigned",
            detail: wasSentForRework ? "The report was returned for rework and is back with the field team." : report.teamName ? `Assigned to ${report.teamName}.` : "Waiting for DMA assignment.",
            active: Boolean(report.teamName) || status !== "new",
            current: status === "assigned"
        },
        {
            title: "Field Repair",
            detail: status === "in_progress" ? "Field work is actively happening on site." : report.engineerSubmissionNotes ? "Engineer submitted repair evidence from the field." : "Awaiting field repair activity.",
            active: [
                "in_progress",
                "pending_approval",
                "approved",
                "closed"
            ].includes(status) || Boolean(report.engineerSubmissionNotes),
            current: status === "in_progress"
        },
        {
            title: "Team Leader Review",
            detail: report.teamLeaderReviewNotes ? report.teamLeaderReviewNotes : status === "pending_approval" ? "Repair evidence passed through team leader review and reached DMA." : "Waiting for team leader review notes.",
            active: [
                "pending_approval",
                "approved",
                "closed"
            ].includes(status) || Boolean(report.teamLeaderReviewNotes),
            current: false
        },
        {
            title: status === "approved" || status === "closed" ? "Resolved and Closed" : wasSentForRework ? "Returned for Rework" : status === "pending_approval" ? "Awaiting DMA Approval" : "DMA Decision",
            detail: status === "approved" || status === "closed" ? report.dmaReviewNotes || "DMA approved the reported leakage resolution and closed the item." : wasSentForRework ? report.dmaReviewNotes || "DMA returned the repair for more field work." : "Waiting for the final DMA decision.",
            active: status === "pending_approval" || Boolean(report.dmaReviewNotes) || status === "approved" || status === "closed",
            current: status === "pending_approval" || status === "approved" || status === "closed" || wasSentForRework
        }
    ];
}
